def test_multiple_path_params():
    router = Router()
    router.add_route('GET', '/users/:user_id/posts/:post_id', lambda req: Response(200, req.params))
    resp = router.handle(Request('GET', '/users/5/posts/10'))
    assert resp.body == {'user_id': '5', 'post_id': '10'}

def test_middleware_modifies_request():
    router = Router()
    class AuthMiddleware(Middleware):
        def process(self, request, next_handler):
            request.headers['user'] = 'admin'
            return next_handler(request)
    router.use(AuthMiddleware())
    router.add_route('GET', '/secure', lambda req: Response(200, req.headers.get('user')))
    resp = router.handle(Request('GET', '/secure'))
    assert resp.body == 'admin'
